	@Test
	void opaquePhysicalAlternativeDoesNotReoptimizeMaterializedChildren() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		Join join = new Join(pattern("s", "p", "o"), pattern("o", "p2", "x"));
		int groupId = memo.intern(join);
		int groupCountBefore = memo.groups().size();
		PhysicalProperties delivered = PhysicalProperties.builder()
				.accessPath("opaque-provider")
				.boundVars(join.getBindingNames())
				.build();

		MemoExpr expression = memo.addPhysicalAlternative(groupId, join.clone(), delivered, "opaque-provider",
				RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), EstimateSnapshot.cascades(CostVector.ZERO),
				true)
				.orElseThrow();

		assertEquals(List.of(), expression.inputGroupIds());
		assertEquals(groupCountBefore, memo.groups().size());
	}

	@Test
	void requiredPropertyRejectionCarriesMismatchDetails() throws Exception {
		PhysicalProperties required = PhysicalProperties.builder()
				.accessPath("directLookup")
				.boundVars(Set.of("s", "o"))
				.materialization(PhysicalProperties.Materialization.MATERIALIZED)
				.build();
		PhysicalProperties delivered = PhysicalProperties.builder()
				.accessPath("prefixScan")
				.boundVars(Set.of("s"))
				.materialization(PhysicalProperties.Materialization.STREAMING)
				.build();

		List<String> missing = missingRequirements(delivered, required);

		assertEquals(List.of("accessPath", "boundVars", "materialization"), missing);
		assertFalse(delivered.satisfies(required));
	}

	@Test
	void inputBoundPhysicalAlternativeDoesNotSatisfyUnboundGoal() throws Exception {
		PhysicalProperties boundLookup = PhysicalProperties.builder()
				.accessPath("directLookup")
				.boundVars(Set.of("s", "p", "o"))
				.inputBoundVars(Set.of("s"))
				.build();

		assertFalse(boundLookup.satisfies(PhysicalProperties.ANY));
		assertTrue(boundLookup.satisfies(PhysicalProperties.builder().boundVars(Set.of("s")).build()));
		assertEquals(List.of("inputBoundVars"), missingRequirements(boundLookup, PhysicalProperties.ANY));
	}

	@Test
	void requiredPropertyWinnerIgnoresCheaperIncompatibleAlternative() throws Exception {
		PhysicalProperties required = PhysicalProperties.builder()
				.accessPath("directLookup")
				.build();
		RuleRegistry registry = RuleRegistry.builder()
				.add(new PropertyImplementationRule("cheap-incompatible",
						PhysicalProperties.builder().accessPath("prefixScan").build(), 1.0d))
				.add(new PropertyImplementationRule("compatible",
						PhysicalProperties.builder().accessPath("directLookup").build(), 100.0d))
				.build();
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				CascadesTelemetry.NO_OP);

		CascadesPlan plan = planner.optimize(pattern("s", "p", "o"), OptimizationGoal.exact(required));
		Winner winner = plan.winner().orElseThrow();

		assertEquals("compatible", winner.provenance().ruleId());
		RejectedAlternative rejected = winner.provenance()
				.rejectedAlternatives()
				.stream()
				.filter(alternative -> "cheap-incompatible".equals(alternative.ruleId()))
				.findFirst()
				.orElseThrow();
		assertEquals(List.of("accessPath"), missingProperties(rejected));
		CascadesPlanProvenanceAnnotator.annotate(winner.plan(), winner.provenance(), "test-planner");
		assertTrue(winner.plan()
				.getStringMetricPlanned("optimizer.cascadesRejectedAlternatives")
				.contains("missing=accessPath"));
	}

	@Test
	void coveredDescendantsDoNotInheritOpaqueWinnerCostVector() {
		Join join = new Join(pattern("s", "p", "o"), pattern("o", "p2", "x"));
		CostVector parentCost = new CostVector(100.0d, 200.0d, 0.0d, 0.0d, 0.0d, 2.0d, 2.0d, 2.0d, 2.0d,
				10.0d, 0.5d, 7.0d);
		EstimateSnapshot parentEstimate = new EstimateSnapshot("test-planner", "opaque-provider",
				"alternative_ranking", 100.0d, 200.0d, parentCost, Map.of(), Map.of());
		RuleProof proof = new RuleProof("opaque-provider", RuleKind.IMPLEMENTATION,
				OptimizationGoal.BAG_SEMANTICS, Set.of("opaque"), "opaque provider owns its subtree");
		PlanProvenance provenance = new PlanProvenance(10, 11, "Join", "opaque-provider",
				RuleKind.IMPLEMENTATION, List.of(), parentEstimate, parentCost, PhysicalProperties.ANY,
				PhysicalProperties.builder().accessPath("opaque-provider").boundVars(join.getBindingNames()).build(),
				List.of(), List.of(proof), false, "");

		CascadesPlanProvenanceAnnotator.annotate(join, provenance, "test-planner");
		CascadesPlanProvenanceAnnotator.annotateFallback(join, "test-planner", "fallback-source",
				"fallback_no_winner", new CostVector(1.0d, 1.0d, 0.0d, 0.0d, 0.0d, 4.0d, 0.0d));

		assertEquals(100.0d, join.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS), 0.0d);
		assertEquals(200.0d, join.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS), 0.0d);
		assertEquals("alternative_ranking",
				join.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE));
		assertCoveredWithoutInheritedNumbers(join.getLeftArg(), "opaque-provider:g10:e11");
		assertCoveredWithoutInheritedNumbers(join.getRightArg(), "opaque-provider:g10:e11");
	}

	@Test
	void fallbackAnnotationReplacesPreviousFallbackMetrics() {
		StatementPattern pattern = pattern("s", "p", "o");
		pattern.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE, "fallback_no_winner");
		pattern.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, 0.0d);
		pattern.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, 0.0d);

		CascadesPlanProvenanceAnnotator.annotateFallback(pattern, "test-planner", "fallback-source",
				"fallback_no_winner", new CostVector(12.0d, 34.0d, 0.0d, 0.0d, 0.0d, 4.0d, 4.0d,
						4.0d, 4.0d, 36.0d, 0.0d, 0.0d));

		assertEquals(12.0d, pattern.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS), 0.0d);
		assertEquals(34.0d, pattern.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS), 0.0d);
		assertEquals("fallback_no_winner",
				pattern.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE));
	}

	@SuppressWarnings("unchecked")
	private static List<String> missingRequirements(PhysicalProperties delivered, PhysicalProperties required)
			throws Exception {
		Method method = PhysicalProperties.class.getMethod("missingRequirements", PhysicalProperties.class);
		return (List<String>) method.invoke(delivered, required);
	}

	@SuppressWarnings("unchecked")
	private static List<String> missingProperties(RejectedAlternative alternative) throws Exception {
		Method method = RejectedAlternative.class.getMethod("missingProperties");
		return (List<String>) method.invoke(alternative);
	}

	private static void assertCoveredWithoutInheritedNumbers(TupleExpr node, String decisionId) {
		assertEquals("covered_by_parent_winner",
				node.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE));
		assertEquals(decisionId, node.getStringMetricPlanned("optimizer.cascadesCoveredByWinner"));
		assertEquals(-1.0d, node.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS), 0.0d);
		assertEquals(-1.0d, node.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS), 0.0d);
		assertEquals(-1.0d, node.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE), 0.0d);
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private static StatementPattern constantPredicatePattern(String predicate) {
		return new StatementPattern(new Var("s"), new Var("p", iri(predicate)), new Var("o"));
	}

	private static Filter predicateFilter(String predicate) {
		return new Filter(pattern("s", "p", "o"), new SameTerm(new Var("p"), new ValueConstant(iri(predicate))));
	}

	private static IRI iri(String value) {
		return SimpleValueFactory.getInstance().createIRI(value);
	}

	private record PropertyImplementationRule(String id, PhysicalProperties delivered, double rows)
			implements CascadesRule {

		@Override
		public RuleKind kind() {
			return RuleKind.IMPLEMENTATION;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return expression.logical();
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 1;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			CostVector cost = CostVector.ofRowsAndWork(rows, rows, QErrorInterval.exact(rows, "test"));
			RuleProof proof = new RuleProof(id, RuleKind.IMPLEMENTATION, OptimizationGoal.BAG_SEMANTICS,
					Set.of("test"), "test physical alternative");
			EstimateSnapshot estimate = new EstimateSnapshot("test-planner", id, "alternative_ranking", rows, rows,
					cost, java.util.Map.of(), java.util.Map.of());
			return List.of(RuleApplication.physical(expression.groupId(), expression.tupleExpr().clone(), delivered,
					cost, proof, id, estimate));
		}
	}
